# -----------------------------
# Version 3D_Mejorado_3niveles_NuevoIngresoURJC
# Nuevas agregaciones
# -----------------------------

# En el nivel 2 queremos subtipo de universidad, pero medido por
# numero de titulaciones ofertadas, no por numero de centros.

def agregar_suma(rows, campos, campo_valor):
    grupos = {}

    for row in rows:
        clave = tuple(row[campo] for campo in campos)

        if clave not in grupos:
            grupos[clave] = {campo: row[campo] for campo in campos}
            grupos[clave][campo_valor] = 0

        grupos[clave][campo_valor] += row[campo_valor]

    return list(grupos.values())


def agregar_universidad_localidad(rows):
    grupos = {}

    for row in rows:
        clave = (
            row["comunidad_autonoma"],
            row["tipo_centro"],
            row["subtipo_centro"],
            row["universidad"],
            row["localidad"]
        )

        if clave not in grupos:
            grupos[clave] = {
                "comunidad_autonoma": row["comunidad_autonoma"],
                "tipo_centro": row["tipo_centro"],
                "subtipo_centro": row["subtipo_centro"],
                "universidad": row["universidad"],
                "localidad": row["localidad"],
                "numero_titulaciones": 0,
                "centros_set": set()
            }

        grupos[clave]["numero_titulaciones"] += row["numero_titulaciones"]
        grupos[clave]["centros_set"].add(row["centro"])

    datos = []

    for item in grupos.values():
        item["numero_centros"] = len(item["centros_set"])
        del item["centros_set"]
        datos.append(item)

    return datos


# Nivel 2: subtipo de universidad por numero de titulaciones

datos_subtipo_titulaciones = agregar_suma(
    datos_titulacion,
    [
        "comunidad_autonoma",
        "tipo_centro",
        "subtipo_centro"
    ],
    "numero_titulaciones"
)


# Nivel 3: universidad + localidad

datos_universidad_localidad = agregar_universidad_localidad(
    datos_titulacion
)


# Orden del eje Z: localidad de mas a menos titulaciones.
# Se calcula por subtipo para que, al filtrar por subtipo de universidad,
# el eje Z quede ordenado dentro de ese subconjunto.

titulaciones_por_subtipo_localidad = {}

for row in datos_universidad_localidad:
    clave = (
        row["comunidad_autonoma"],
        row["tipo_centro"],
        row["subtipo_centro"],
        row["localidad"]
    )
    titulaciones_por_subtipo_localidad[clave] = (
        titulaciones_por_subtipo_localidad.get(clave, 0)
        + row["numero_titulaciones"]
    )

orden_localidades = {}

grupos_subtipo = {}
for clave, total in titulaciones_por_subtipo_localidad.items():
    clave_subtipo = clave[:3]
    localidad = clave[3]
    grupos_subtipo.setdefault(clave_subtipo, []).append((localidad, total))

for clave_subtipo, valores in grupos_subtipo.items():
    valores_ordenados = sorted(
        valores,
        key=lambda item: (-item[1], item[0])
    )

    for indice, (localidad, total) in enumerate(valores_ordenados, start=1):
        orden_localidades[clave_subtipo + (localidad,)] = f"{indice:02d} {localidad}"

for row in datos_universidad_localidad:
    clave = (
        row["comunidad_autonoma"],
        row["tipo_centro"],
        row["subtipo_centro"],
        row["localidad"]
    )
    row["localidad_ordenada"] = orden_localidades[clave]


def ordenar_por_localidad_y_titulaciones(row):
    return (
        row["subtipo_centro"],
        row["localidad_ordenada"],
        row["universidad"]
    )


datos_universidad_localidad = sorted(
    datos_universidad_localidad,
    key=ordenar_por_localidad_y_titulaciones
)

# Escalado visual para el nivel 3.
# Se multiplica por 3 el campo usado como radio/tamano de las esferas
# para que todos los puntos se vean mas grandes en la escena.

for row in datos_universidad_localidad:
    row["radio_titulaciones"] = row["numero_titulaciones"] * 3


# Grafico 4: centro + tipo_titulacion

datos_centro_tipo_titulacion = agregar_suma(
    datos_titulacion,
    [
        "comunidad_autonoma",
        "tipo_centro",
        "subtipo_centro",
        "universidad",
        "localidad",
        "centro",
        "tipo_titulacion"
    ],
    "numero_titulaciones"
)

# El campo anterior usa localidad normal para el filtro.
# Agregamos localidad_ordenada despues, con el mismo criterio del nivel 3.
for row in datos_centro_tipo_titulacion:
    clave = (
        row["comunidad_autonoma"],
        row["tipo_centro"],
        row["subtipo_centro"],
        row["localidad"]
    )
    row["localidad_ordenada"] = orden_localidades.get(clave, row["localidad"])

# Orden fijo del eje Z del grafico 4.
# Se fuerza el orden: Grado, Doble grado, Master, Doctorado y Resto.
# Las programaciones conjuntas se muestran como Doble grado.

def obtener_tipo_titulacion_visual(row):
    tipo_original = row.get("tipo_titulacion", "")
    titulacion = row.get("titulacion", "")

    if tipo_original == "Doctorado":
        return "Doctorado"
    if tipo_original == "Master":
        return "Master"
    if tipo_original == "Programaciones Conjuntas de Estudios Oficiales":
        return "Doble grado"
    if "+" in titulacion or "Doble" in titulacion:
        return "Doble grado"
    if tipo_original == "Grado":
        return "Grado"
    return "Resto"

orden_fijo_tipos_titulacion = {
    "Resto": "01 Resto",
    "Doctorado": "02 Doctorado",
    "Master": "03 Master",
    "Doble grado": "04 Doble grado",
    "Grado": "05 Grado"
}

for row in datos_centro_tipo_titulacion:
    row["tipo_titulacion_visual"] = obtener_tipo_titulacion_visual(row)
    row["tipo_titulacion_ordenado"] = orden_fijo_tipos_titulacion.get(
        row["tipo_titulacion_visual"],
        "01 Resto"
    )




